function isCompanyVerified(company){
  return company?.verified===true||(company?.approved===true&&company?.profileComplete!==false&&company?.documentsVerified!==false&&company?.paymentVerified!==false&&company?.adminVerified!==false);
}
function isMemberVerified(member){return member?.verified===true}
function verifiedBadge(kind='company'){
  return `<span class="verified-badge ${kind==='member'?'member-verified':''}" title="IDI verified: requirements complete and approved by an administrator" aria-label="IDI verified">✓</span>`;
}

