let activePublicPartnerFilter='all';
function renderPublicPartners(){const rows=partnerOrganizations.filter(partner=>partner.verified!==false&&(activePublicPartnerFilter==='all'||partner.type===activePublicPartnerFilter));document.getElementById('publicPartnerGrid').innerHTML=rows.map(partner=>{const index=partnerOrganizations.indexOf(partner);return `<article class="public-partner-card"><div class="public-partner-head"><span class="public-partner-logo" style="background:${partner.color}">${initials(partner.name)}</span><div><h3>${partner.name}</h3><p>${partner.type} • ${partner.location}</p></div><span class="public-partner-verified">●</span></div><p class="public-partner-focus">${partner.focus}</p><div class="tags">${partner.sectors.map(sector=>`<span class="tag">${sector}</span>`).join('')}</div><div class="public-partner-facts"><div><span>Investment / value</span><strong>${partner.ticket}</strong></div><div><span>Preferred stage</span><strong>${partner.stage}</strong></div><div><span>Core capability</span><strong>${partner.capability}</strong></div></div><button class="secondary public-partner-button" data-public-partner="${index}">View organization →</button></article>`}).join('');document.getElementById('publicPartnerCount').textContent=`Showing ${rows.length} verified ${activePublicPartnerFilter==='all'?'capital and strategic partners':activePublicPartnerFilter.toLowerCase()+' organizations'}`;document.querySelectorAll('[data-public-partner]').forEach(button=>button.onclick=()=>openPublicPartner(Number(button.dataset.publicPartner)))}
document.getElementById('publicPartnerFilters').onclick=e=>{if(!e.target.dataset.publicPartnerFilter)return;activePublicPartnerFilter=e.target.dataset.publicPartnerFilter;document.querySelectorAll('[data-public-partner-filter]').forEach(button=>button.classList.toggle('active',button===e.target));renderPublicPartners()};
const publicPartnerModal=document.getElementById('publicPartnerModal');
function openPublicPartner(index){const partner=partnerOrganizations[index];if(!partner)return;const services=[partner.capability,'Business introductions','Campaign collaboration','Ecosystem access'];document.getElementById('publicPartnerProfile').innerHTML=`<header class="public-partner-profile-head"><span class="public-partner-profile-logo" style="background:${partner.color}">${initials(partner.name)}</span><div><h2>${partner.name}</h2><p>✓ Verified ${partner.type} • ${partner.location}</p></div></header><div class="public-partner-profile-body"><div><h3>Organization overview</h3><p>${partner.focus}</p><div class="partner-profile-sectors">${partner.sectors.map(sector=>`<span>${sector}</span>`).join('')}</div><h3>How this partner supports businesses</h3><div class="partner-profile-services">${services.map(service=>`<div><strong>${service}</strong><span>Available through the IDI APP ecosystem</span></div>`).join('')}</div></div><aside class="partner-profile-side"><h3>Investment profile</h3><dl><dt>Organization type</dt><dd>${partner.type}</dd><dt>Investment / value</dt><dd>${partner.ticket}</dd><dt>Preferred stage</dt><dd>${partner.stage}</dd><dt>Primary markets</dt><dd>${partner.location}</dd><dt>Focus sectors</dt><dd>${partner.sectors.join(', ')}</dd></dl><button class="primary partner-public-login">Member login to connect</button></aside></div>`;publicPartnerModal.classList.add('open');publicPartnerModal.setAttribute('aria-hidden','false');publicPartnerModal.querySelector('.partner-public-login').onclick=()=>{closePublicPartner();openLogin()}}
function closePublicPartner(){publicPartnerModal.classList.remove('open');publicPartnerModal.setAttribute('aria-hidden','true')}
document.querySelectorAll('[data-public-partner-close]').forEach(button=>button.onclick=closePublicPartner);publicPartnerModal.onclick=e=>{if(e.target===publicPartnerModal)closePublicPartner()};

