const generatedCompanyLogo=company=>{
  const seed=[...company.name].reduce((sum,char)=>sum+char.charCodeAt(0),0),suffix=(company.name.match(/\d+$/)?.[0]||'').slice(-2),mark=`${initials(company.name)}${suffix}`;
  const svg=`<svg xmlns="http://www.w3.org/2000/svg" width="160" height="160" viewBox="0 0 160 160"><rect width="160" height="160" rx="30" fill="#fff"/><rect x="7" y="7" width="146" height="146" rx="26" fill="${company.color}"/><circle cx="${36+seed%42}" cy="${31+seed%28}" r="${38+seed%17}" fill="#fff" opacity=".13"/><path d="M16 ${112-seed%20} L${92+seed%38} 15 L150 ${69+seed%35} V150 H16Z" fill="#071c54" opacity=".15"/><text x="80" y="93" text-anchor="middle" fill="#fff" font-family="Arial,sans-serif" font-size="${mark.length>3?38:48}" font-weight="800">${mark}</text><text x="80" y="126" text-anchor="middle" fill="#fff" opacity=".82" font-family="Arial,sans-serif" font-size="11" font-weight="700" letter-spacing="1">${company.industry.toUpperCase().slice(0,16)}</text></svg>`;
  return `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`;
};
