function formatNewsDate(value){if(!value)return 'Just now';return new Intl.DateTimeFormat('en-GB',{dateStyle:'medium',timeStyle:'short'}).format(new Date(value))}
function newsParagraphs(value){return String(value||'').split(/\n\s*\n/).filter(Boolean).map(p=>`<p>${p.replace(/\n/g,'<br>')}</p>`).join('')}
const newsArticleModal=document.getElementById('newsArticleModal');
function openNewsArticle(index){const n=newsItems[index];if(!n)return;const gallery=n.photos?.length?`<section class="news-photo-gallery">${n.photos.map((photo,i)=>`<figure style="background-image:url('${photo}')"><figcaption>Article photo ${i+1}</figcaption></figure>`).join('')}</section>`:'';document.getElementById('newsArticleContent').innerHTML=`<header class="news-story-header"><span class="story-section">${n.category||'Investment News'}</span><h1>${n.headline}</h1><p class="story-tagline">${n.tagline||''}</p><div class="story-byline"><div class="story-author">${initials(n.author||n.source)}</div><div><strong>By ${n.author||n.source}</strong><span>${formatNewsDate(n.publishAt)} • ${n.dateline||'Cambodia'} • ${Math.max(2,Math.ceil(String(n.details||'').split(/\s+/).length/180))} min read</span></div></div></header><figure class="news-story-hero ${n.heroImage||n.thumbnail?'has-image':''}" ${n.heroImage||n.thumbnail?`style="background-image:url('${n.heroImage||n.thumbnail}')"`:''}><span>UNI VENTURECONNECT NEWS</span></figure>${n.imageCaption?`<p class="story-caption">${n.imageCaption}</p>`:''}<div class="news-story-layout"><main class="story-body">${newsParagraphs(n.details||n.tagline)}${gallery}<div class="story-hashtags">${(n.hashtags||[]).map(tag=>`<span>${tag}</span>`).join('')}</div></main><aside class="story-sidebar"><strong>Story information</strong><dl><dt>Source</dt><dd>${n.source}</dd><dt>Classification</dt><dd>Level ${n.level} — ${n.level===3?'Restricted':n.level===2?'Strategic':'Public'}</dd><dt>Audience</dt><dd>${n.audiences.join(', ')}</dd><dt>Distribution</dt><dd>${n.channels.join(', ')}</dd></dl><button class="primary story-share">Share article</button></aside></div>`;newsArticleModal.classList.add('open');newsArticleModal.setAttribute('aria-hidden','false');document.querySelector('.story-share').onclick=()=>showToast('Article link ready','The secure news link is ready to share with eligible members.')}
function closeNewsArticle(){newsArticleModal.classList.remove('open');newsArticleModal.setAttribute('aria-hidden','true')}
const openNewsArticleBase=openNewsArticle;openNewsArticle=function(index){openNewsArticleBase(index);const label=document.querySelector('.news-story-hero>span');if(label)label.textContent='IDI APP NEWS'};
document.querySelectorAll('[data-article-close]').forEach(b=>b.onclick=closeNewsArticle);
