document.getElementById('memberRegistrationForm').onsubmit=e=>{e.preventDefault();const form=new FormData(e.target),password=String(form.get('password')),confirmPassword=String(form.get('confirmPassword'));if(password!==confirmPassword){showToast('Passwords do not match','Please enter the same password in both fields.');return}const email=String(form.get('email')).toLowerCase(),applications=JSON.parse(localStorage.getItem('idi-member-applications')||'[]');if(applications.some(application=>application.email===email)||members.some(member=>member.email.toLowerCase()===email)){showToast('Email already registered','Sign in or contact the membership team for assistance.');return}const reference=`IDI-MEM-${String(Date.now()).slice(-6)}`,application={reference,name:form.get('fullName'),email,phone:form.get('phone'),position:form.get('position'),applicantType:form.get('applicantType'),organization:form.get('organization')||'Individual',industry:form.get('industry'),location:form.get('location'),website:form.get('website'),membership:form.get('membership'),status:'Pending verification',submittedAt:new Date().toISOString()};applications.push(application);localStorage.setItem('idi-member-applications',JSON.stringify(applications));members.unshift({name:application.name,email:application.email,org:application.organization,tier:application.membership,status:'Pending',renewal:'After approval',channels:'Email',verified:false});renderMembers();document.getElementById('memberRegistrationReference').textContent=reference;e.target.style.display='none';document.getElementById('memberRegistrationSuccess').classList.add('show');showToast('Application submitted','Your membership application is now pending verification.');e.target.reset()};

const investmentStages=[
  {name:'Verified onboarding',duration:'1–5 days',owner:'Compliance lead',gate:'Identity cleared',companyAction:'Submit KYB, owners, authority',investorAction:'Submit KYC, mandate, source of funds',documents:['Registration and licenses','Directors and beneficial owners','Authorized signatory evidence','Investor mandate and fund profile'],checks:['Identity and authority verified','Sanctions, PEP and adverse-media screening','Conflicts disclosed by both parties','Data privacy consent recorded']},
  {name:'Funding request & mandate',duration:'2–7 days',owner:'Investment manager',gate:'Mandate fit confirmed',companyAction:'Define ask, use of funds, instrument',investorAction:'Define ticket, sectors, stage, geography',documents:['Funding request','Pitch deck and financial model','Investment mandate','Eligibility and exclusion criteria'],checks:['Funding need is specific','Investor has authority and capacity','Instrument and currency identified','No mandate conflict']},
  {name:'Match & mutual interest',duration:'2–10 days',owner:'Relationship manager',gate:'Both parties opt in',companyAction:'Review investor profile and consent',investorAction:'Review teaser and express interest',documents:['Blind teaser','Match rationale','Conflict declaration','Mutual interest record'],checks:['Company accepts introduction','Investor accepts introduction','Conflicts cleared','Communication owner assigned']},
  {name:'NDA & secure data room',duration:'1–5 days',owner:'Legal coordinator',gate:'Confidential access active',companyAction:'Sign NDA and upload indexed files',investorAction:'Sign NDA and name review team',documents:['Mutual NDA','Data-room index','Access permissions','Q&A protocol'],checks:['NDA executed by authorized signatories','Least-privilege access applied','Documents version-controlled','Audit log activated']},
  {name:'Screening & indication',duration:'1–3 weeks',owner:'Deal lead',gate:'IOI / screening approval',companyAction:'Pitch, answer questions, confirm terms',investorAction:'Initial commercial and risk screening',documents:['Management presentation','Screening memo','Indicative valuation','Indication of interest'],checks:['Business and market fit assessed','Financial quality reviewed','Key risks logged','Proceed / decline decision recorded']},
  {name:'Term sheet',duration:'1–3 weeks',owner:'Deal lead + counsel',gate:'Term sheet signed',companyAction:'Negotiate economics and governance',investorAction:'Propose structure and conditions',documents:['Term sheet','Capitalization table','Valuation analysis','Exclusivity / no-shop terms'],checks:['Economics approved','Governance and reserved matters agreed','Conditions precedent listed','Non-binding / binding clauses identified']},
  {name:'Full due diligence',duration:'3–8 weeks',owner:'DD workstream leads',gate:'All red flags resolved',companyAction:'Respond across all workstreams',investorAction:'Run legal, financial, tax, ESG review',documents:['Financial and tax reports','Legal and IP report','Commercial / technical report','ESG and impact assessment'],checks:['Material findings classified','Remediation owners and deadlines set','Data verified against source evidence','Final DD report accepted']},
  {name:'IC & final approval',duration:'1–2 weeks',owner:'Investment committee secretary',gate:'Documented approval',companyAction:'Confirm final disclosures and CP plan',investorAction:'Submit memo and vote independently',documents:['Investment memorandum','Risk and ESG summary','Final term comparison','Committee minutes / resolution'],checks:['Quorum and conflicts recorded','Decision rationale documented','Approval limits respected','Conditions and expiry date recorded']},
  {name:'Legal closing & funds',duration:'2–6 weeks',owner:'Transaction counsel',gate:'Funds and securities confirmed',companyAction:'Satisfy CPs and issue securities',investorAction:'Final AML check and transfer funds',documents:['Definitive agreements','Board / shareholder approvals','Closing checklist and CP evidence','Payment and ownership confirmation'],checks:['Legal documents executed','Bank and source-of-funds verified','Funds received in verified account','Registry / cap table updated']},
  {name:'Monitoring, value creation & exit',duration:'Investment life',owner:'Portfolio manager',gate:'Ongoing governance',companyAction:'Report KPIs, covenants and impact',investorAction:'Monitor, support, follow-on or exit',documents:['Reporting pack','Board materials','Covenant and impact reports','Exit / repayment documentation'],checks:['Reporting calendar active','Issues and remediation tracked','Valuation and ownership updated','Exit proceeds and lessons recorded']}
];
