function renderInvestmentFlow(){document.getElementById('investmentStageList').innerHTML=investmentStages.map((stage,index)=>`<button class="investment-stage ${index===activeInvestmentStage?'active':''}" data-investment-stage="${index}"><span class="stage-party company"><i>Co</i><span><strong>${stage.companyAction}</strong><small>Company responsibility</small></span></span><span class="stage-center"><span>${index+1}</span><strong>${stage.name}</strong><small>${stage.duration}</small></span><span class="stage-party investor"><span><strong>${stage.investorAction}</strong><small>Investor responsibility</small></span><i>Inv</i></span></button>`).join('');document.querySelectorAll('[data-investment-stage]').forEach(button=>button.onclick=()=>{activeInvestmentStage=Number(button.dataset.investmentStage);renderInvestmentFlow()});const stage=investmentStages[activeInvestmentStage];document.getElementById('investmentStageDetail').innerHTML=`<h2>Stage ${activeInvestmentStage+1}: ${stage.name}</h2><p>The case advances only when the gate owner confirms the evidence and both parties' required actions.</p><div class="stage-detail-meta"><div><span>ACCOUNTABLE OWNER</span><strong>${stage.owner}</strong></div><div><span>TARGET DURATION</span><strong>${stage.duration}</strong></div><div><span>EXIT GATE</span><strong>${stage.gate}</strong></div></div><div class="stage-checklists"><div><h3>Required documents</h3>${stage.documents.map(item=>`<p>${item}</p>`).join('')}</div><div><h3>Completion checklist</h3>${stage.checks.map(item=>`<p>${item}</p>`).join('')}</div></div>`;document.getElementById('investmentGateList').innerHTML=investmentGates.map((gate,index)=>`<div class="gate-item ${gate[2]==='Pending'?'pending':''}"><span>${gate[2]==='Complete'?'✓':'!'}</span><div><strong>${gate[0]}</strong><small>${gate[1]}</small></div><b>${gate[2]}</b></div>`).join('');renderInvestmentCases()}
function renderInvestmentCases(){const q=document.getElementById('investmentCaseSearch').value.toLowerCase(),rows=investmentCases.filter(item=>(item.company+item.investor+item.instrument+investmentStages[item.stage].name).toLowerCase().includes(q));document.getElementById('investmentCaseTable').innerHTML=rows.map((item,index)=>{const progress=(item.stage+1)*10;return `<tr><td><div class="table-company"><div class="logo" style="background:#173f96">⇄</div><div><strong>${item.company}</strong><span>${item.investor}</span></div></div></td><td>${item.instrument}</td><td>${investmentStages[item.stage].name}</td><td><div class="investment-progress"><div class="investment-progress-track"><i style="width:${progress}%"></i></div>${progress}%</div></td><td>${item.next}</td><td><span class="risk-pill ${item.risk.toLowerCase()}">${item.risk}</span></td><td><button class="row-action" data-investment-case="${index}">⋯</button></td></tr>`}).join('');document.getElementById('activeInvestmentCases').textContent=18+Math.max(0,investmentCases.length-5);document.querySelectorAll('[data-investment-case]').forEach(button=>button.onclick=()=>{const item=rows[Number(button.dataset.investmentCase)];showToast('Investment case controls',`${item.company} ↔ ${item.investor}: advance gate, request evidence, record decision, or close case.`)})}
const investmentCaseModal=document.getElementById('investmentCaseModal');
function openInvestmentCase(){investmentCaseModal.classList.add('open')}
function closeInvestmentCase(){investmentCaseModal.classList.remove('open')}
document.getElementById('startInvestmentCase').onclick=openInvestmentCase;
document.querySelectorAll('[data-investment-case-close]').forEach(button=>button.onclick=closeInvestmentCase);
document.getElementById('investmentCaseSearch').oninput=renderInvestmentCases;
document.getElementById('investmentCaseForm').onsubmit=e=>{e.preventDefault();const form=new FormData(e.target);investmentCases.unshift({company:form.get('company'),investor:form.get('investor'),instrument:form.get('instrument'),stage:0,next:`Complete verified onboarding • ${form.get('targetDate')}`,risk:'Low'});closeInvestmentCase();renderInvestmentFlow();showToast('Investment case created',`${form.get('company')} and ${form.get('investor')} must now complete Gate 1 verification.`);e.target.reset()};

