const membershipPrices={VIP:{USD:500,KHR:2000000,benefits:['All intelligence levels','Priority investor access','VIP events','SMS alerts','Exclusive campaigns']},Premium:{USD:250,KHR:1000000,benefits:['Level 1–2 news','Partner discovery','Pitching programs','Member events']},Standard:{USD:120,KHR:480000,benefits:['Member news','Verified directory','Public campaigns','Open events']}};
let activeBillingTier='Standard';
const formatBillingDate=value=>new Intl.DateTimeFormat('en-GB',{day:'2-digit',month:'short',year:'numeric'}).format(new Date(`${value}T12:00:00`));
const dateKey=date=>{const y=date.getFullYear(),m=String(date.getMonth()+1).padStart(2,'0'),d=String(date.getDate()).padStart(2,'0');return `${y}-${m}-${d}`};
function effectiveExpiry(profile){return localStorage.getItem(`idi-membership-expiry-${profile.email}`)||profile.membershipExpires||''}
function daysToExpiry(value){if(!value)return null;const now=new Date();now.setHours(0,0,0,0);const expiry=new Date(`${value}T00:00:00`);return Math.round((expiry-now)/86400000)}
function renewalStage(days){if(days===null)return'upgrade';if(days>30)return'active';if(days>7)return'month';if(days>0)return'week';if(days===0)return'today';if(days>=-30)return'expired';return'overdue'}
function renewalCopy(stage,days){return{active:['Membership active',`${days} days remain in your current membership period.`],month:['Renewal due within one month',`Your membership expires in ${days} days. Renew early to keep uninterrupted access.`],week:['Urgent: membership expires soon',`Only ${days} day${days===1?'':'s'} remain. Complete renewal now to avoid an access interruption.`],today:['Membership expires today','Renew today to keep your current membership benefits and content access.'],expired:['Membership expired',`Your membership expired ${Math.abs(days)} day${Math.abs(days)===1?'':'s'} ago. Renew to restore full access.`],overdue:['Membership renewal overdue',`Your membership is ${Math.abs(days)} days overdue. Payment is required to reactivate member access.`],upgrade:['Upgrade from Guest access','Choose a paid membership to unlock member news, partners, campaigns, and events.']}[stage]}
function renderRenewalCenter(profile){const banner=document.getElementById('membershipRenewalBanner');if(profile.isAdmin){banner.className='renewal-banner';return}activeBillingTier=profile.tier==='Guest'?'Standard':profile.tier;const expiry=effectiveExpiry(profile),days=daysToExpiry(expiry),stage=renewalStage(days),copy=renewalCopy(stage,days);banner.className=`renewal-banner ${stage}`;if(stage!=='active')banner.classList.add('show');document.getElementById('renewalBannerTitle').textContent=copy[0];document.getElementById('renewalBannerText').textContent=copy[1];document.getElementById('billingStatusCard').className=`billing-status-card ${stage}`;document.getElementById('billingStatusLabel').textContent=stage==='upgrade'?'MEMBERSHIP UPGRADE':stage.toUpperCase().replace('MONTH','30-DAY NOTICE').replace('WEEK','7-DAY NOTICE');document.getElementById('billingStatusTitle').textContent=copy[0];document.getElementById('billingStatusText').textContent=copy[1];document.getElementById('billingDaysRemaining').textContent=days===null?'Choose a plan':days>0?`${days} days`:days===0?'Due today':`${Math.abs(days)} days late`;document.getElementById('billingPlanName').textContent=`${activeBillingTier} Membership`;document.getElementById('billingOrganization').textContent=profile.organization;document.getElementById('billingTierSeal').textContent=activeBillingTier==='VIP'?'◆':activeBillingTier[0];document.getElementById('billingExpiryDate').textContent=expiry?formatBillingDate(expiry):'Not applicable';const base=expiry&&new Date(`${expiry}T12:00:00`)>new Date()?new Date(`${expiry}T12:00:00`):new Date();const nextStart=new Date(base);nextStart.setDate(nextStart.getDate()+1);const nextEnd=new Date(nextStart);nextEnd.setFullYear(nextEnd.getFullYear()+Number(document.getElementById('renewalTerm').value));nextEnd.setDate(nextEnd.getDate()-1);document.getElementById('billingNewPeriod').textContent=`${new Intl.DateTimeFormat('en-GB',{day:'2-digit',month:'short',year:'numeric'}).format(nextStart)} – ${new Intl.DateTimeFormat('en-GB',{day:'2-digit',month:'short',year:'numeric'}).format(nextEnd)}`;document.getElementById('billingAccessStatus').textContent=stage==='expired'||stage==='overdue'?'Restricted':stage==='upgrade'?'Guest':'Active';document.getElementById('billingBenefits').innerHTML=membershipPrices[activeBillingTier].benefits.map(item=>`<span>✓ ${item}</span>`).join('');renderBillingAmounts();renderBillingHistory(profile)}
function renderBillingAmounts(){const term=Number(document.getElementById('renewalTerm').value),currency=document.getElementById('paymentCurrency').value,unit=membershipPrices[activeBillingTier][currency],total=unit*term,formatted=currency==='USD'?`$${total.toFixed(2)}`:`៛${total.toLocaleString('en-US')}`;document.getElementById('invoicePlanLabel').textContent=`${activeBillingTier} membership × ${term} year${term>1?'s':''}`;document.getElementById('invoiceSubtotal').textContent=formatted;document.getElementById('invoiceTotal').textContent=formatted;document.getElementById('khqrAmount').textContent=formatted;document.getElementById('khqrPlan').textContent=`${activeBillingTier} Membership • ${term} year${term>1?'s':''}`;if(currentMember)renderRenewalCenterPeriodOnly(currentMember,term)}
function renderRenewalCenterPeriodOnly(profile,term){const expiry=effectiveExpiry(profile),base=expiry&&new Date(`${expiry}T12:00:00`)>new Date()?new Date(`${expiry}T12:00:00`):new Date(),start=new Date(base);start.setDate(start.getDate()+1);const end=new Date(start);end.setFullYear(end.getFullYear()+term);end.setDate(end.getDate()-1);document.getElementById('billingNewPeriod').textContent=`${new Intl.DateTimeFormat('en-GB',{day:'2-digit',month:'short',year:'numeric'}).format(start)} – ${new Intl.DateTimeFormat('en-GB',{day:'2-digit',month:'short',year:'numeric'}).format(end)}`}
function renderBillingHistory(profile){const saved=JSON.parse(localStorage.getItem(`idi-payment-history-${profile.email}`)||'[]'),base=profile.tier==='Guest'?[]:[{invoice:'IDI-2025-0018',date:'28 Jul 2025',amount:profile.tier==='VIP'?'$500.00':profile.tier==='Premium'?'$250.00':'$120.00',method:'ABA KHQR',status:'Paid'}],rows=[...saved,...base];document.getElementById('billingHistory').innerHTML=rows.length?rows.map(row=>`<div class="billing-history-row"><strong>${row.invoice}</strong><span>${row.date}</span><span>${row.method}</span><em>${row.status}</em><button>Receipt</button></div>`).join(''):'<div class="billing-empty-history">No membership payments yet.</div>'}
document.getElementById('renewalTerm').onchange=renderBillingAmounts;document.getElementById('paymentCurrency').onchange=renderBillingAmounts;document.getElementById('downloadInvoice').onclick=()=>showToast('Invoice prepared','Your membership renewal invoice is ready for download in production.');
