function calculateScore(){const f=new FormData(document.getElementById('applicationForm'));const vals=['model','market','team','finance','product'].map(k=>Number(f.get(k)));const score=Math.round(vals.reduce((a,b)=>a+b,0)*2);document.getElementById('liveScore').textContent=`${score} / 100`;return score}
document.querySelectorAll('input[type=range]').forEach(r=>r.addEventListener('input',calculateScore));
document.getElementById('applicationForm').onsubmit=e=>{e.preventDefault();const f=new FormData(e.target),score=calculateScore();const status=score>=85?'Investor Ready':score>=70?'Strong Potential':'Need Improvement';pitches.unshift({name:f.get('company'),industry:f.get('industry'),stage:f.get('stage'),complete:80,score,status,date:'28 Jun 2026',color:'#5b4bdb'});renderPitches();closeModal();navigate('pitching');showToast('Application analyzed',`${f.get('company')} scored ${score}/100 — ${status}.`);e.target.reset();calculateScore()};

function showToast(title,msg){const t=document.getElementById('toast');t.querySelector('strong').textContent=title;t.querySelector('p').textContent=msg;t.classList.add('show');clearTimeout(window.toastTimer);window.toastTimer=setTimeout(()=>t.classList.remove('show'),3200)}
const loginModal=document.getElementById('loginModal');
function openLogin(prefill){loginModal.classList.add('open');loginModal.setAttribute('aria-hidden','false');if(prefill&&loginProfiles[prefill])loginModal.querySelector('[name="email"]').value=loginProfiles[prefill].email}
function closeLogin(){loginModal.classList.remove('open');loginModal.setAttribute('aria-hidden','true')}
['headerLogin','heroLogin','footerLogin'].forEach(id=>document.getElementById(id).onclick=()=>openLogin());
document.getElementById('quickLogin').onclick=()=>openLogin();
const directoryIntro=document.querySelector('#public-directory .directory-intro'),directoryListButton=document.getElementById('listCompanyButton');
if(directoryIntro&&directoryListButton){
  const actions=document.createElement('div');
  actions.className='directory-intro-actions';
  actions.innerHTML='<button class="secondary directory-login-trigger"><img src="assets/idi-logo.jpg" alt="" /> Member login</button>';
  actions.append(directoryListButton);
  directoryIntro.append(actions);
  actions.querySelector('.directory-login-trigger').onclick=()=>openLogin();
  const legend=document.createElement('div');
  legend.className='verification-legend';
  legend.innerHTML=`${verifiedBadge()} <span>Blue tick means the company completed all requirements and was approved by an IDI administrator.</span>`;
  document.querySelector('#public-directory .public-directory-filters')?.insertAdjacentElement('beforebegin',legend);
}
document.getElementById('adminLogin').onclick=()=>openLogin('admin');
document.querySelectorAll('[data-login-close]').forEach(b=>b.onclick=closeLogin);
document.querySelectorAll('[data-demo]').forEach(b=>b.onclick=()=>loginAs(b.dataset.demo));
const DEMO_PASSWORD='IdiDemo#2026';
function profileFromRow(row,fallback){if(!row)return fallback;return{name:row.name,email:fallback.email,tier:row.tier,role:row.role,organization:row.organization,membershipExpires:row.membership_expires,paymentStatus:row.payment_status,verified:row.verified,isAdmin:row.is_admin,canPublish:row.can_publish,canCampaign:row.can_campaign,allowed:row.allowed_pages||fallback.allowed}}
function applyMemberSession(profile){currentMember=profile;document.body.classList.toggle('admin-session',!!profile.isAdmin);closeLogin();document.getElementById('landingPage').style.display='none';document.querySelectorAll('.app-shell').forEach(el=>el.classList.add('authenticated'));document.getElementById('sidebarName').textContent=profile.name;document.getElementById('sidebarInitials').textContent=initials(profile.name);document.getElementById('sidebarRole').textContent=`${profile.role} • ${profile.organization}`;document.getElementById('memberTierChip').textContent=profile.tier;document.getElementById('dashboardEyebrow').textContent=profile.isAdmin?'WEBSITE ADMIN CONTROL CENTER':`${profile.tier.toUpperCase()} MEMBER DASHBOARD`;document.getElementById('dashboardGreeting').textContent=profile.isAdmin?'Website administration':`Good morning, ${profile.name.split(' ')[0]}.`;document.getElementById('dashboardSubtitle').textContent=profile.isAdmin?'Manage public content, members, companies, investments, events, partners, and platform activity.':`Personalized opportunities and updates for ${profile.organization}.`;document.querySelectorAll('.nav-item[data-page]').forEach(n=>n.classList.toggle('access-hidden',!profile.allowed.includes(n.dataset.page)));const accessCopy={VIP:['VIP full ecosystem access','Immediate investment intelligence, exclusive campaigns, priority events, and investor connections.'],Premium:['Premium member access','Selected investment news, pitching programs, partner discovery, and member events.'],Standard:['Standard member access','Member news, verified directory, public campaigns, and ecosystem events.'],Guest:['Guest access','General announcements, public directory information, and open events.']}[profile.tier];document.getElementById('accessTitle').textContent=profile.isAdmin?'Full platform administration':profile.canCampaign?`${profile.role} workspace`:accessCopy[0];document.getElementById('accessDescription').textContent=profile.isAdmin?'Publish homepage news, manage public events and registrations, approve companies, control memberships, and review the complete ecosystem.':profile.canCampaign?'Create campaigns, review opportunities, manage meetings, and connect with qualified companies.':accessCopy[1];document.getElementById('openNewsComposer').style.display=profile.canPublish?'':'none';document.querySelector('.distribution-panel').style.display=profile.canPublish?'':'none';document.querySelectorAll('.campaign-create').forEach(b=>b.style.display=profile.canCampaign||profile.canPublish?'':'none');const statSets={Admin:[['9','Companies awaiting approval'],['6','News publications'],['327','Event registrations'],['5,516','Platform members']],VIP:[['24','New opportunities'],['6','Exclusive news'],['8','Event invitations'],['12','Partner matches']],Premium:[['7','Pitch updates'],['4','Member news'],['5','Saved partners'],['3','Event invitations']],Standard:[['3','New directory leads'],['2','Member news'],['1','Active application'],['4','Upcoming events']],Guest:[['1,248','Directory listings'],['3','General news'],['6','Open events'],['0','Saved items']]};document.querySelectorAll('.stat-card').forEach((card,i)=>{card.querySelector('strong').textContent=statSets[profile.tier][i][0];card.querySelector('span').textContent=statSets[profile.tier][i][1];card.querySelector('small').style.display='none'});renderAdminNews();renderPublicDirectory();renderRenewalCenter(profile);renderFundingAccess(profile);navigate('overview');if(listingRequested){listingRequested=false;openCompanyListing()}}
async function loginAs(key){const fallbackProfile=loginProfiles[key]||loginProfiles.guest;if(supabaseClient){const{data,error}=await supabaseClient.auth.signInWithPassword({email:fallbackProfile.email,password:DEMO_PASSWORD});if(error){showToast('Demo login unavailable',`${error.message} — has this demo account been created in Supabase yet?`);return}const row=await loadProfile(data.user.id);applyMemberSession(profileFromRow(row,fallbackProfile));return}localStorage.setItem('uni-member-session',key);applyMemberSession(fallbackProfile)}
document.getElementById('loginForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),email=String(f.get('email')).toLowerCase(),password=String(f.get('password'));if(supabaseClient){const{data,error}=await supabaseClient.auth.signInWithPassword({email,password});if(error){showToast('Login unsuccessful',error.message);return}const row=await loadProfile(data.user.id);applyMemberSession(profileFromRow(row,{email,...loginProfiles.guest}));return}const match=Object.entries(loginProfiles).find(([,p])=>p.email.toLowerCase()===email);if(match?.[1].isAdmin&&password!==match[1].password){showToast('Admin login unsuccessful','Please check the administrator password.');return}loginAs(match?match[0]:'guest')};
document.getElementById('logoutButton').onclick=async()=>{if(supabaseClient)await supabaseClient.auth.signOut();localStorage.removeItem('uni-member-session');currentMember=null;document.body.classList.remove('admin-session');document.querySelectorAll('.app-shell').forEach(el=>el.classList.remove('authenticated'));document.getElementById('landingPage').style.display='block';window.scrollTo({top:0,behavior:'smooth'})};
document.getElementById('profileButton').onclick=()=>showToast('Member profile',`${currentMember?.name} • ${currentMember?.tier} • ${currentMember?.organization}`);
document.getElementById('runScreening').onclick=()=>{showToast('AI screening started','12 applications are being checked for completeness and quality.');document.getElementById('sidebar').classList.remove('open')};
document.getElementById('globalSearch').addEventListener('keydown',e=>{if(e.key==='Enter'){document.getElementById('companySearch').value=e.target.value;navigate('directory');renderDirectory()}});
document.addEventListener('keydown',e=>{if((e.metaKey||e.ctrlKey)&&e.key==='k'){e.preventDefault();document.getElementById('globalSearch').focus()}if(e.key==='Escape'){closeModal();closeNewsModal();closeNewsArticle();closePublicEventRegistration();closePublicPartner();closeKhqrCheckout();closeCompanyProfile();closeCompanyListing();closeMemberRegistration();closeStaffModal();closeInvestmentCase();dealModal.classList.remove('open')}});

async function bootstrapData(){
  if(supabaseClient){
    const[dbCompanies,dbNews,dbEvents]=await Promise.all([loadCompanies(),loadNews(),loadEvents()]);
    if(dbCompanies.length)companies=dbCompanies;
    if(dbNews.length)newsItems=dbNews;
    if(dbEvents.length)events=dbEvents;
  }
  renderChart();renderActivity();renderTopCompanies();renderDirectory();renderPublicDirectory();renderPublicPartners();renderInvestmentFlow();renderInvestmentOperations();renderFundingRequests();renderCompanyVerification();renderPitches();renderEvents();renderPublicEvents();renderAdminNews();renderPartners();renderMembers();renderDeals();renderConversations();renderReports();renderAdminStaff();renderStaffPermissionPreview();
  if(supabaseClient){
    const{data:{session}}=await supabaseClient.auth.getSession();
    if(session){const row=await loadProfile(session.user.id);if(row)applyMemberSession(profileFromRow(row,{email:session.user.email,...loginProfiles.guest}))}
    return;
  }
  const savedSession=localStorage.getItem('uni-member-session');if(savedSession&&loginProfiles[savedSession])loginAs(savedSession);
}
bootstrapData();
